1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
3	const CURSED_SURCHARGE_PERCENT = 50;
4	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_PERCENT = 20;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	
9	const BASE_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
19	const BLOCK_SIZE = 3;
20	const BLOCK_PRICE = 60;
21	
22	const INSURANCE_VALUES: Record<string, number> = {
23	  sword: 1000,
24	  amulet: 600,
25	  staff: 800,
26	  potion: 400,
27	  rune: 250,
28	  moonstone: 250,
29	};
30	
31	const DEDUCTIBLE = 100;
32	const CAP_MULTIPLIER = 2;
33	
34	const itemBasePremium = (item: any): number => BASE_PREMIUMS[item.type];
35	
36	const sumItemPremiums = (items: any[]): number =>
37	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
38	
39	const groupByType = (items: any[]): Record<string, any[]> =>
40	  items.reduce((groups, item) => {
41	    (groups[item.type] ||= []).push(item);
42	    return groups;
43	  }, {} as Record<string, any[]>);
44	
45	const isCompleteBlock = (type: string, group: any[]): boolean =>
46	  COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE;
47	
48	const groupPremium = (type: string, group: any[]): number =>
49	  isCompleteBlock(type, group) ? BLOCK_PRICE : sumItemPremiums(group);
50	
51	const calculateBasePremium = (items: any[]): number =>
52	  Object.entries(groupByType(items)).reduce(
53	    (total, [type, group]) => total + groupPremium(type, group),
54	    0
55	  );
56	
57	const percentOf = (amount: number, percent: number): number =>
58	  (amount * percent) / 100;
59	
60	type Rule<T> = { applies: (target: T) => boolean; percent: number };
61	
62	const ITEM_SURCHARGE_RULES: Rule<any>[] = [
63	  { applies: (item) => item.cursed, percent: CURSED_SURCHARGE_PERCENT },
64	  {
65	    applies: (item) => item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD,
66	    percent: HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
67	  },
68	];
69	
70	const FOLLOW_UP_DISCOUNT_PERCENT = 15;
71	
72	type PolicyContext = { customer: any; isFollowUp: boolean };
73	
74	const POLICY_MODIFIER_RULES: Rule<PolicyContext>[] = [
75	  { applies: () => true, percent: FIRST_INSURANCE_SURCHARGE_PERCENT },
76	  {
77	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
78	    percent: -LOYALTY_DISCOUNT_PERCENT,
79	  },
80	  {
81	    applies: ({ isFollowUp }) => isFollowUp,
82	    percent: -FOLLOW_UP_DISCOUNT_PERCENT,
83	  },
84	];
85	
86	const sumRulePercentages = <T>(rules: Rule<T>[], target: T, base: number): number =>
87	  rules.reduce(
88	    (sum, rule) => sum + (rule.applies(target) ? percentOf(base, rule.percent) : 0),
89	    0
90	  );
91	
92	const itemSurcharge = (item: any): number =>
93	  sumRulePercentages(ITEM_SURCHARGE_RULES, item, itemBasePremium(item));
94	
95	const calculateItemSurcharges = (items: any[]): number =>
96	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
97	
98	const calculatePolicyModifiers = (context: PolicyContext, policyBase: number): number =>
99	  sumRulePercentages(POLICY_MODIFIER_RULES, context, policyBase);
100	
101	const quotePremium = (items: any[], context: PolicyContext): number => {
102	  const policyBase = calculateBasePremium(items);
103	  const itemSurcharges = calculateItemSurcharges(items);
104	  const policyModifiers = calculatePolicyModifiers(context, policyBase);
105	  return Math.ceil(policyBase + policyModifiers + itemSurcharges + PROCESSING_FEE);
106	};
107	
108	const itemInsuranceValue = (item: any): number => INSURANCE_VALUES[item.type];
109	
110	const calculateInsuranceSum = (items: any[]): number =>
111	  items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
112	
113	const calculateDamagePayout = (damage: any): number =>
114	  Math.max(0, Math.floor(damage.amount - DEDUCTIBLE));
115	
116	const sumDamagePayouts = (damages: any[]): number =>
117	  damages.reduce((sum, damage) => sum + calculateDamagePayout(damage), 0);
118	
119	type Policy = { remainingCap: number };
120	
121	const processClaim = (step: any, policies: Policy[]) => {
122	  const policy = policies[step.policy];
123	  const payout = Math.min(sumDamagePayouts(step.incident.damages), policy.remainingCap);
124	  policy.remainingCap -= payout;
125	  return { payout, remainingCap: policy.remainingCap };
126	};
127	
128	const processQuote = (step: any, index: number, customer: any, policies: Policy[]) => {
129	  const premium = quotePremium(step.items, { customer, isFollowUp: index > 0 });
130	  const insuranceSum = calculateInsuranceSum(step.items);
131	  policies.push({ remainingCap: CAP_MULTIPLIER * insuranceSum });
132	  return { premium };
133	};
134	
135	const processStep = (step: any, index: number, customer: any, policies: Policy[]) =>
136	  step.op === "claim"
137	    ? processClaim(step, policies)
138	    : processQuote(step, index, customer, policies);
139	
140	export const runScenario = (scenario: any): unknown => {
141	  const policies: Policy[] = [];
142	  return {
143	    results: scenario.steps.map((step: any, index: number) =>
144	      processStep(step, index, scenario.customer, policies)
145	    ),
146	  };
147	};
